var e=[{id:`L2_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`……가끔씩, 그런 생각을 해.`,JPN:`……時々考えるの。`,ENG:`... I often think of our fate.`,TWN:`……我時常會想，`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`만약 처음부터 이렇게 될 줄 알았다면……`,JPN:`もしこうなってしまうってわかっていたなら……`,ENG:`Had we known things would happen like this...`,TWN:`如果當初知道事情會變成這樣……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`우린 지금과는 달라졌을까?`,JPN:`私たちは今と違っていたのかな？`,ENG:`Would we have made different choices?`,TWN:`我們的結局會不會和現在不同呢？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`의미없는 후회라는 건 알아.`,JPN:`後悔しても意味ないってわかってる。`,ENG:`I know my regret means nothing.`,TWN:`我知道後悔無濟於事。`},stage:{bg:`CA_YOOMINA_03`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`인간도, 신도 지나가 버린 운명을 되돌릴 수는 없으니까.`,JPN:`人間も、神も過ぎ去った運命を巻き戻すことはできないから。`,ENG:`No man or god can change the past.`,TWN:`無論是人類還是神仙，都無法讓時光倒流。`},stage:{bg:`CA_YOOMINA_03`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`그러니까…… 너는 나처럼 바보 같은 선택을 하지 않길 바래.`,JPN:`だから……あなたは私みたいな誤った選択はしないでほしいの。`,ENG:`So, please do not make the same foolish mistake I made.`,TWN:`所以……我希望你別像我一樣做出愚蠢的選擇。`},stage:{bg:`CA_YOOMINA_03`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`가끔은, 포기하는 편이 더 나을 때도 있으니까.`,JPN:`たまには、諦めた方がいい時もあるから。`,ENG:`Sometimes it's better to give up rather than hold on.`,TWN:`有時候，放棄也許會更好一些。`},stage:{bg:`CA_YOOMINA_03`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`그러니까…… 안녕.`,JPN:`だから……さようなら。`,ENG:`So, farewell.`,TWN:`所以……再見了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`SHE_NPC_NULL_NULL`,text:{KOREA:`이제 헤어질 시간이야.`,JPN:`もうお別れの時間ね。`,ENG:`It's time for us to part ways. `,TWN:`離別時刻到了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L30_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`네, 부사장님. 지금 막 공항 라운지에 도착했습니다.`,JPN:`はい、副社長。今ちょうど空港のラウンジに着きました。`,ENG:`Yes, Madame Vice President. I just arrived at the airport lounge.`,TWN:`是，副總。我剛剛抵達了機場貴賓室。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L33_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`네. 주무시고 계시네요. 비행기를 오래 타서 피곤하신가 봐요.`,JPN:`はい、眠っていますね。長時間のフライトでお疲れのようです。`,ENG:`Yes, he's sleeping. Must be exhausted from his long plane trip.`,TWN:`是，他正在閉目養神，應該是因為長時間飛行的關係，所以有點疲憊。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_NEW_02`,slots:{L:null,C:null,R:null}}},{id:`L37_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`아, 잠시만요. 지금 깨어나신 것 같아요.`,JPN:`あ、お待ちください。今お目覚めになったみたいです。`,ENG:`Oh, wait. He just woke up.`,TWN:`咦，請等一下，他好像醒了。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_NEW_02`,slots:{L:null,C:null,R:null}}},{id:`L38_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`다시 연락드리겠습니다, 부사장님.`,JPN:`それではまた連絡します。失礼します。`,ENG:`I'll call you right back.`,TWN:`我等會再聯繫副總。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_NEW_02`,slots:{L:null,C:null,R:null}}}];export{e as default};